code.javascript:
function intersection(nums1, nums2) {
  const first = new Set(nums1);
  const out = new Set();
  for (const n of nums2) {
    if (first.has(n)) {
      out.add(n);
    }
  }
  return [...out].sort((a, b) => a - b);
}

